 28→// ---------------------------------------------------------------------------
 29→// SDK Config translation
 30→// ---------------------------------------------------------------------------
 31→
 32→type SdkConfig = {
 33→  model?: string;
 34→  mcp?: Record<string, { type: "remote"; url: string; headers?: Record<string, string> }>;
 35→  agent?: {
 36→    build?: {
 37→      permission?: {
 38→        edit?: "allow" | "ask" | "deny";
 39→        bash?: "allow" | "ask" | "deny";
 40→        webfetch?: "allow" | "ask" | "deny";
 41→      };
 42→    };
 43→  };
 44→};
 45→
 46→function toSdkConfig(config: OpencodeConfig): SdkConfig {
 47→  const mcp: SdkConfig["mcp"] = {};
 48→  for (const [name, server] of Object.entries(config.mcpServers)) {
 49→    mcp[name] = {
 50→      type: "remote" as const,
 51→      url: server.url,
 52→      headers: server.headers,
 53→    };
 54→  }
 55→
 56→  const permissionMap: Record<string, "allow" | "ask" | "deny"> = {};
 57→  for (const perm of config.permissions.autoApprove) {
 58→    permissionMap[perm] = "allow";
 59→  }
 60→
 61→  return {
 62→    model: `${config.model.provider}/${config.model.model}`,
 63→    mcp,
 64→    agent: {
 65→      build: {
 66→        permission: {
 67→          edit: permissionMap["edit"] ?? permissionMap["write"] ?? "allow",
 68→          bash: permissionMap["bash"] ?? "allow",
 69→          webfetch: permissionMap["webfetch"] ?? "deny",
 70→        },
 71→      },
 72→    },
 73→  };
 74→}
