119→// ---------------------------------------------------------------------------
120→// Event iteration — port (dependencies as function signatures)
121→// ---------------------------------------------------------------------------
122→
123→export type EventIterationDeps = {
124→  emitEvent: (streamId: string, event: StreamEvent) => void;
125→  updateSessionStatus: (
126→    sessionId: string,
127→    status: OrchestratorStatus,
128→    error?: string,
129→  ) => Promise<void>;
130→  updateLastEventAt: (sessionId: string) => Promise<void>;
131→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
132→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
133→};
134→
135→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
136→  TERMINAL_ORCHESTRATOR_STATUSES,
137→);
138→
139→/**
140→ * Iterates the OpenCode event stream, forwarding events through the event
141→ * bridge. Transitions session to "active" on first event, starts stall
142→ * detection, and stops on terminal status or error.
143→ *
144→ * Returns a Promise that resolves when iteration ends (for testing).
145→ * In production, this is launched fire-and-forget.
146→ */
147→export function startEventIteration(
148→  deps: EventIterationDeps,
149→  eventStream: AsyncIterable<unknown>,
150→  streamId: string,
151→  sessionId: string,
152→): Promise<void> {
153→  const stallDetector = deps.startStallDetector(sessionId, streamId);
154→
155→  const bridge = startEventBridge(
156→    {
157→      emitEvent: deps.emitEvent,
158→      updateLastEventAt: deps.updateLastEventAt,
159→    },
160→    streamId,
161→    sessionId,
162→    stallDetector,
163→  );
164→
165→  let firstEventReceived = false;
166→
167→  async function iterate(): Promise<void> {
168→    try {
169→      for await (const rawEvent of eventStream) {
170→        // Check if session has reached terminal status
171→        const currentStatus = await deps.getSessionStatus(sessionId);
172→        if (TERMINAL_STATUSES.has(currentStatus)) {
173→          break;
174→        }
175→
176→        // Transition to active on first event
177→        if (!firstEventReceived) {
178→          firstEventReceived = true;
179→          await deps.updateSessionStatus(sessionId, "active");
180→        }
181→
182→        // Forward through event bridge (transform + emit + stall detection)
183→        bridge.handleEvent(rawEvent as OpencodeEvent);
184→      }
185→    } catch (err) {
186→      const errorMessage = err instanceof Error ? err.message : String(err);
187→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
188→    } finally {
189→      bridge.stop();
190→    }
191→  }
192→
193→  return iterate();
194→}
