200→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
201→  const result: Record<string, unknown> = {};
202→  for (const [key, value] of Object.entries(obj)) {
203→    if (value !== undefined && value !== null) {
204→      result[key] = value;
205→    }
206→  }
207→  return result as Partial<T>;
208→}
