254→async function lookupSession(
255→  surreal: Surreal,
256→  sessionId: string,
257→): Promise<SessionLookup> {
258→  const record = new RecordId("agent_session", sessionId);
259→  const session = await surreal.select<SessionRow>(record);
260→  if (!session) {
261→    return { ok: false, error: sessionNotFound(sessionId) };
262→  }
263→  if (!session.orchestrator_status) {
264→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
265→  }
266→  const status = session.orchestrator_status as OrchestratorStatus;
267→  return { ok: true, session, record, status };
268→}
