314→export async function createOrchestratorSession(
315→  input: CreateSessionInput,
316→): Promise<OrchestratorSessionResult> {
317→  // 1. Validate assignment eligibility
318→  const assignmentResult = await input.validateAssignment(
319→    input.surreal,
320→    input.workspaceId,
321→    input.taskId,
322→  );
323→
324→  if (!assignmentResult.ok) {
325→    return { ok: false, error: fromAssignmentError(assignmentResult.error) };
326→  }
327→
328→  const { validation } = assignmentResult;
329→  const taskSlug = slugFromTitle(validation.title);
330→  const repoRoot = validation.repoPath;
331→
332→  // 2. Create worktree
333→  const worktreeResult = await createWorktree(
334→    input.shellExec,
335→    repoRoot,
336→    taskSlug,
337→  );
338→
339→  if (!worktreeResult.ok) {
340→    return {
341→      ok: false,
342→      error: worktreeError(worktreeResult.error.message),
343→    };
344→  }
345→
346→  const { branchName, worktreePath } = worktreeResult.value;
347→
348→  // 3. Create agent_session record
349→  const { session_id: agentSessionId } = await input.createAgentSession({
350→    surreal: input.surreal,
351→    agent: "opencode",
352→    workspaceRecord: validation.workspaceRecord,
353→    taskId: input.taskId,
354→  });
355→
356→  const streamId = generateStreamId(agentSessionId);
357→
358→  // 4. Build config and spawn OpenCode
359→  const config = buildOpencodeConfig({
360→    brainBaseUrl: input.brainBaseUrl,
361→    workspaceId: input.workspaceId,
362→    authToken: input.authToken,
363→  });
364→
365→  const spawnFn = input.spawnOpenCode ?? defaultSpawnOpenCode;
366→  let handle: OpenCodeHandle;
367→  try {
368→    handle = await spawnFn(config, worktreePath, input.taskId);
369→  } catch (err) {
370→    // Rollback: remove worktree and delete agent_session on spawn failure
371→    await removeWorktree(input.shellExec, repoRoot, branchName);
372→    const sessionRecord = new RecordId("agent_session", agentSessionId);
373→    await input.surreal.delete(sessionRecord);
374→    return {
375→      ok: false,
376→      error: worktreeError(`Failed to spawn OpenCode: ${err instanceof Error ? err.message : String(err)}`),
377→    };
378→  }
379→
380→  // 5. Register handle for later abort
381→  handleRegistry.set(agentSessionId, handle);
382→
383→  // 6. Update agent_session with orchestrator fields
384→  const sessionRecord = new RecordId("agent_session", agentSessionId);
385→  await input.surreal.update(sessionRecord).merge({
386→    orchestrator_status: "spawning" as OrchestratorStatus,
387→    worktree_branch: branchName,
388→    worktree_path: worktreePath,
389→    opencode_session_id: handle.sessionId,
390→    stream_id: streamId,
391→  });
392→
393→  return {
394→    ok: true,
395→    value: {
396→      agentSessionId,
397→      streamId,
398→      worktreeBranch: branchName,
399→    },
400→  };
401→}
402→
403→// Default spawn -- placeholder for production use
404→async function defaultSpawnOpenCode(
405→  _config: OpencodeConfig,
406→  _worktreePath: string,
407→  _taskId: string,
408→): Promise<OpenCodeHandle> {
409→  throw new Error(
410→    "spawnOpenCode not provided -- must be injected for production use",
411→  );
412→}
