448→// abortOrchestratorSession
449→// ---------------------------------------------------------------------------
450→
451→type AbortSessionInput = {
452→  surreal: Surreal;
453→  shellExec: ShellExec;
454→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
455→  sessionId: string;
456→  endAgentSession: (input: {
457→    surreal: Surreal;
458→    workspaceRecord: RecordId<"workspace", string>;
459→    sessionId: string;
460→    summary: string;
461→  }) => Promise<{ session_id: string; ended: boolean }>;
462→};
463→
464→export async function abortOrchestratorSession(
465→  input: AbortSessionInput,
466→): Promise<AbortSessionResult> {
467→  const lookup = await lookupSession(input.surreal, input.sessionId);
468→  if (!lookup.ok) {
469→    return { ok: false, error: lookup.error };
470→  }
471→  const { session, record: sessionRecord } = lookup;
472→
473→  // 1. Kill the OpenCode process if handle exists
474→  const handle = handleRegistry.get(input.sessionId);
475→  if (handle) {
476→    handle.abort();
477→    handleRegistry.delete(input.sessionId);
478→  }
479→
480→  // 2. Update orchestrator_status to aborted
481→  await input.surreal.update(sessionRecord).merge({
482→    orchestrator_status: "aborted" as OrchestratorStatus,
483→  });
484→
485→  const workspaceRecord = requireWorkspace(session, input.sessionId);
486→
487→  // 3. Remove worktree if branch name exists
488→  if (session.worktree_branch) {
489→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
490→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
491→  }
492→
493→  // 4. Return task to ready
494→  if (session.task_id) {
495→    await input.surreal.update(session.task_id).merge({
496→      status: "ready",
497→      updated_at: new Date(),
498→    });
499→  }
500→
501→  // 5. End the agent session
502→  await input.endAgentSession({
503→    surreal: input.surreal,
504→    workspaceRecord,
505→    sessionId: input.sessionId,
506→    summary: "Session aborted",
507→  });
508→
509→  return {
510→    ok: true,
511→    value: {
512→      aborted: true,
513→      sessionId: input.sessionId,
514→    },
515→  };
516→}
