519→// acceptOrchestratorSession
520→// ---------------------------------------------------------------------------
521→
522→type AcceptSessionInput = {
523→  surreal: Surreal;
524→  sessionId: string;
525→  summary: string;
526→  endAgentSession: (input: {
527→    surreal: Surreal;
528→    workspaceRecord: RecordId<"workspace", string>;
529→    sessionId: string;
530→    summary: string;
531→  }) => Promise<{ session_id: string; ended: boolean }>;
