533→
534→export async function acceptOrchestratorSession(
535→  input: AcceptSessionInput,
536→): Promise<AcceptSessionResult> {
537→  const lookup = await lookupSession(input.surreal, input.sessionId);
538→  if (!lookup.ok) {
539→    return { ok: false, error: lookup.error };
540→  }
541→  const { session, record: sessionRecord, status } = lookup;
542→
543→  if (!ACCEPTABLE_STATUSES.has(status)) {
544→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
545→  }
546→
547→  const workspaceRecord = requireWorkspace(session, input.sessionId);
548→
549→  // 1. Update orchestrator_status to completed
550→  await input.surreal.update(sessionRecord).merge({
551→    orchestrator_status: "completed" as OrchestratorStatus,
552→  });
553→
554→  // 2. Mark task as done
555→  if (session.task_id) {
556→    await input.surreal.update(session.task_id).merge({
557→      status: "done",
558→      updated_at: new Date(),
559→    });
560→  }
561→
562→  // 3. Clean up handle registry
563→  handleRegistry.delete(input.sessionId);
564→
565→  // 4. End the agent session
566→  await input.endAgentSession({
567→    surreal: input.surreal,
568→    workspaceRecord,
569→    sessionId: input.sessionId,
570→    summary: input.summary,
571→  });
572→
573→  return {
574→    ok: true,
575→    value: {
576→      accepted: true,
577→      sessionId: input.sessionId,
578→    },
579→  };
580→}
