582→// ---------------------------------------------------------------------------
583→// State guard helpers
584→// ---------------------------------------------------------------------------
585→
586→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
587→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
588→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
589→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
590→
591→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
592→  return {
593→    code: "SESSION_ERROR",
594→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
595→    httpStatus: 409,
596→  };
597→}
598→
599→function sessionAborted(sessionId: string): SessionError {
600→  return {
601→    code: "SESSION_ERROR",
602→    message: `Session ${sessionId} has been aborted`,
603→    httpStatus: 409,
604→  };
605→}
