607→// ---------------------------------------------------------------------------
608→// getOrchestratorReview
609→// ---------------------------------------------------------------------------
610→
611→type GetReviewInput = {
612→  surreal: Surreal;
613→  sessionId: string;
614→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
615→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
616→  getTaskTitle: (taskId: string) => Promise<string>;
617→};
618→
619→export async function getOrchestratorReview(
620→  input: GetReviewInput,
621→): Promise<ReviewResult> {
622→  const lookup = await lookupSession(input.surreal, input.sessionId);
623→  if (!lookup.ok) {
624→    return { ok: false, error: lookup.error };
625→  }
626→  const { session, status } = lookup;
627→
628→  if (status === "aborted") {
629→    return { ok: false, error: sessionAborted(input.sessionId) };
630→  }
631→
632→  if (!REVIEWABLE_STATUSES.has(status)) {
633→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
634→  }
635→
636→  // Get diff from the branch
637→  const branchName = session.worktree_branch ?? "";
638→  const workspaceRecord = requireWorkspace(session, input.sessionId);
639→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
640→  const diffResult = await input.getDiff(repoRoot, branchName);
641→
642→  const diff = diffResult.ok
643→    ? diffResult.value
644→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
645→
646→  // Get task title
647→  const taskId = session.task_id ? session.task_id.id : "";
648→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
649→
650→  return {
651→    ok: true,
652→    value: {
653→      taskTitle,
654→      diff,
655→      session: {
656→        orchestratorStatus: status,
657→        ...pickDefined({
658→          worktreeBranch: session.worktree_branch,
659→          startedAt: session.started_at,
660→          lastEventAt: session.last_event_at,
661→        }),
662→      },
663→    },
664→  };
665→}
