667→// ---------------------------------------------------------------------------
668→// rejectOrchestratorSession
669→// ---------------------------------------------------------------------------
670→
671→type RejectSessionInput = {
672→  surreal: Surreal;
673→  sessionId: string;
674→  feedback: string;
675→};
676→
677→export async function rejectOrchestratorSession(
678→  input: RejectSessionInput,
679→): Promise<RejectSessionResult> {
680→  const lookup = await lookupSession(input.surreal, input.sessionId);
681→  if (!lookup.ok) {
682→    return { ok: false, error: lookup.error };
683→  }
684→  const { session, record: sessionRecord, status } = lookup;
685→
686→  if (!REJECTABLE_STATUSES.has(status)) {
687→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
688→  }
689→
690→  // 1. Update session status to active (agent resumes work)
691→  await input.surreal.update(sessionRecord).merge({
692→    orchestrator_status: "active" as OrchestratorStatus,
693→    last_feedback: input.feedback,
694→  });
695→
696→  // 2. Return task to in_progress
697→  if (session.task_id) {
698→    await input.surreal.update(session.task_id).merge({
699→      status: "in_progress",
700→      updated_at: new Date(),
701→    });
702→  }
703→
704→  return {
705→    ok: true,
706→    value: {
707→      rejected: true,
708→      continuing: true,
709→    },
710→  };
711→}
