713→// ---------------------------------------------------------------------------
714→// sendSessionPrompt
715→// ---------------------------------------------------------------------------
716→
717→type SendPromptInput = {
718→  surreal: Surreal;
719→  sessionId: string;
720→  text: string;
721→};
722→
723→export async function sendSessionPrompt(
724→  input: SendPromptInput,
725→): Promise<PromptSessionResult> {
726→  const lookup = await lookupSession(input.surreal, input.sessionId);
727→  if (!lookup.ok) {
728→    return { ok: false, error: lookup.error };
729→  }
730→  const { status } = lookup;
731→
732→  if (!PROMPTABLE_STATUSES.has(status)) {
733→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
734→  }
735→
736→  const handle = handleRegistry.get(input.sessionId);
737→  if (!handle) {
738→    return {
739→      ok: false,
740→      error: {
741→        code: "SESSION_ERROR",
742→        message: `Cannot prompt session ${input.sessionId}: agent handle not available (server may have restarted)`,
743→        httpStatus: 409,
744→      },
745→    };
746→  }
747→
748→  // Fire-and-forget: deliver prompt to the agent process
749→  handle.sendPrompt(input.text).catch(() => {
750→    // Prompt delivery failure is non-fatal; the session continues
751→  });
752→
753→  return {
754→    ok: true,
755→    value: { delivered: true },
756→  };
757→}
