 16→export async function runInit(): Promise<void> {
 17→  const serverUrl = process.env.BRAIN_SERVER_URL ?? DEFAULT_SERVER_URL;
 18→  const workspaceId = process.env.BRAIN_WORKSPACE_ID;
 19→
 20→  const gitRoot = findGitRoot(process.cwd());
 21→  if (!gitRoot) {
 22→    console.error("Not inside a git repository. Run brain init from a project directory.");
 23→    process.exit(1);
 24→  }
 25→
 26→  if (!workspaceId) {
 27→    console.error("Set BRAIN_WORKSPACE_ID env var to your workspace ID.");
 28→    console.error("Find it in the Brain web UI or the database.");
 29→    process.exit(1);
 30→  }
 31→
 32→  console.log("Brain Init\n──────────\n");
 33→
 34→  // Step 1: Auth
 35→  await setupAuth(serverUrl, workspaceId, gitRoot);
 36→
 37→  // Step 2: .mcp.json
 38→  await setupMcpJson(gitRoot);
 39→
 40→  // Step 3: .claude/settings.json hooks
 41→  await setupClaudeHooks(gitRoot);
 42→
 43→  // Step 4: CLAUDE.md
 44→  await setupClaudeMd(gitRoot);
 45→
 46→  // Step 5: Commands
 47→  await setupCommands(gitRoot);
 48→
 49→  // Step 6: Git hooks
 50→  installGitHooks(gitRoot);
 51→
 52→  console.log(`\nDone. Restart Claude Code to activate.`);
 53→}
