 55→// ---------------------------------------------------------------------------
 56→// Step 1: Auth (OAuth 2.1 PKCE)
 57→// ---------------------------------------------------------------------------
 58→
 59→const DEFAULT_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
 60→
 61→function base64url(buf: Buffer): string {
 62→  return buf.toString("base64url");
 63→}
 64→
 65→function generatePkce(): { verifier: string; challenge: string } {
 66→  const verifier = base64url(randomBytes(32));
 67→  const challenge = base64url(createHash("sha256").update(verifier).digest());
 68→  return { verifier, challenge };
 69→}
 70→
 71→export async function setupAuth(
 72→  serverUrl: string,
 73→  workspaceId: string,
 74→  gitRoot: string,
 75→  options?: { openUrl?: (url: string) => void },
 76→): Promise<void> {
 77→  const global = await loadGlobalConfig();
 78→  const existing = global?.repos[gitRoot];
 79→  if (existing && existing.workspace === workspaceId && existing.access_token) {
 80→    console.log(`✓ Auth: already configured for ${gitRoot}`);
 81→    return;
 82→  }
 83→
 84→  // 1. Verify workspace exists
 85→  try {
 86→    await BrainHttpClient.listProjects(serverUrl, workspaceId);
 87→  } catch {
 88→    console.error(`Workspace ${workspaceId} not found on ${serverUrl}`);
 89→    process.exit(1);
 90→  }
 91→
 92→  // 2. Dynamic Client Registration
 93→  const dcrRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
 94→    method: "POST",
 95→    headers: { "Content-Type": "application/json" },
 96→    body: JSON.stringify({
 97→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
 98→      redirect_uris: ["http://127.0.0.1/callback"],
 99→      grant_types: ["authorization_code", "refresh_token"],
100→      response_types: ["code"],
101→      token_endpoint_auth_method: "none",
102→    }),
103→  });
104→  if (!dcrRes.ok) {
105→    throw new Error(`Client registration failed: ${dcrRes.status} ${await dcrRes.text()}`);
106→  }
107→  const { client_id } = await dcrRes.json() as { client_id: string };
108→
109→  // 3. PKCE
110→  const pkce = generatePkce();
111→  const state = base64url(randomBytes(16));
112→
113→  // 4. Start local callback server
114→  const { promise: codePromise, resolve: resolveCode, reject: rejectCode } = Promise.withResolvers<string>();
115→
116→  const callbackServer = Bun.serve({
117→    port: 0,
118→    hostname: "127.0.0.1",
119→    routes: {
120→      "/callback": (request) => {
121→        const url = new URL(request.url);
122→        const code = url.searchParams.get("code");
123→        const returnedState = url.searchParams.get("state");
124→        const error = url.searchParams.get("error");
125→
126→        if (error) {
127→          rejectCode(new Error(`OAuth error: ${error}`));
128→          return new Response("<html><body><h1>Authentication failed</h1><p>You can close this tab.</p></body></html>", {
129→            headers: { "Content-Type": "text/html" },
130→          });
131→        }
132→        if (returnedState !== state) {
133→          rejectCode(new Error("state mismatch"));
134→          return new Response("<html><body><h1>State mismatch</h1></body></html>", {
135→            headers: { "Content-Type": "text/html" },
136→          });
137→        }
138→        if (!code) {
139→          rejectCode(new Error("no code returned"));
140→          return new Response("<html><body><h1>No authorization code</h1></body></html>", {
141→            headers: { "Content-Type": "text/html" },
142→          });
143→        }
144→
145→        resolveCode(code);
146→        return new Response("<html><body><h1>Authenticated!</h1><p>You can close this tab and return to the terminal.</p></body></html>", {
147→          headers: { "Content-Type": "text/html" },
148→        });
149→      },
150→    },
151→  });
152→
153→  const redirectUri = `http://127.0.0.1:${callbackServer.port}/callback`;
154→
155→  // Update redirect_uris with actual port (re-register)
156→  const dcrUpdateRes = await fetch(`${serverUrl}/api/auth/oauth2/register`, {
157→    method: "POST",
158→    headers: { "Content-Type": "application/json" },
159→    body: JSON.stringify({
160→      client_name: `brain-cli-${workspaceId.slice(0, 8)}`,
161→      redirect_uris: [redirectUri],
162→      grant_types: ["authorization_code", "refresh_token"],
163→      response_types: ["code"],
164→      token_endpoint_auth_method: "none",
165→    }),
166→  });
167→  if (!dcrUpdateRes.ok) {
168→    callbackServer.stop();
169→    throw new Error(`Client re-registration failed: ${dcrUpdateRes.status} ${await dcrUpdateRes.text()}`);
170→  }
171→  const dcrUpdate = await dcrUpdateRes.json() as { client_id: string };
172→  const actualClientId = dcrUpdate.client_id;
173→
174→  // 5. Open browser
175→  const authUrl = new URL(`${serverUrl}/api/auth/oauth2/authorize`);
176→  authUrl.searchParams.set("client_id", actualClientId);
177→  authUrl.searchParams.set("redirect_uri", redirectUri);
178→  authUrl.searchParams.set("response_type", "code");
179→  authUrl.searchParams.set("scope", DEFAULT_SCOPES);
180→  authUrl.searchParams.set("code_challenge", pkce.challenge);
181→  authUrl.searchParams.set("code_challenge_method", "S256");
182→  authUrl.searchParams.set("state", state);
183→  // Pass resource so better-auth issues a JWT access token (not opaque)
184→  authUrl.searchParams.set("resource", serverUrl);
185→
186→  console.log("Opening browser for authentication...");
187→  console.log(`If the browser doesn't open, visit: ${authUrl.toString()}\n`);
188→
189→  const openUrl = options?.openUrl ?? ((url: string) => {
190→    const openCmd = process.platform === "darwin" ? "open" : process.platform === "win32" ? "start" : "xdg-open";
191→    Bun.spawn([openCmd, url], { stdout: "ignore", stderr: "ignore" });
192→  });
193→  openUrl(authUrl.toString());
194→
195→  // 6. Wait for callback
196→  let code: string;
197→  try {
198→    code = await codePromise;
199→  } catch (error) {
200→    callbackServer.stop();
201→    throw error;
202→  }
203→
204→  // 7. Exchange code for tokens
205→  const tokenRes = await fetch(`${serverUrl}/api/auth/oauth2/token`, {
206→    method: "POST",
207→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
208→    body: new URLSearchParams({
209→      grant_type: "authorization_code",
210→      code,
211→      redirect_uri: redirectUri,
212→      client_id: actualClientId,
213→      code_verifier: pkce.verifier,
214→      resource: serverUrl,
215→    }),
216→  });
217→
218→  callbackServer.stop();
219→
220→  if (!tokenRes.ok) {
221→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
222→  }
223→
224→  const tokens = await tokenRes.json() as {
225→    access_token: string;
226→    refresh_token: string;
227→    expires_in: number;
228→    token_type: string;
229→  };
230→
231→  // 8. Store tokens
232→  await saveRepoConfig(serverUrl, gitRoot, {
233→    workspace: workspaceId,
234→    client_id: actualClientId,
235→    access_token: tokens.access_token,
236→    refresh_token: tokens.refresh_token,
237→    token_expires_at: Math.floor(Date.now() / 1000) + tokens.expires_in,
238→  });
239→
240→  console.log(`✓ Auth: OAuth tokens saved for ${gitRoot}`);
241→}
