247→export async function setupMcpJson(gitRoot: string): Promise<void> {
248→  const mcpPath = join(gitRoot, ".mcp.json");
249→  const file = Bun.file(mcpPath);
250→  let mcp: { mcpServers: Record<string, unknown> } = { mcpServers: {} };
251→
252→  if (await file.exists()) {
253→    try {
254→      mcp = await file.json();
255→      mcp.mcpServers ??= {};
256→    } catch {
257→      // Corrupted file — overwrite
258→    }
259→  }
260→
261→  mcp.mcpServers.brain = { command: "brain", args: ["mcp"] };
262→  await Bun.write(mcpPath, JSON.stringify(mcp, null, 2) + "\n");
263→  console.log("✓ MCP: .mcp.json updated");
264→}
