268→// ---------------------------------------------------------------------------
269→
270→type HookEntry = { type: string; command?: string; prompt?: string };
271→type SettingsHookGroup = { matcher?: string; hooks: HookEntry[] };
272→
273→export async function setupClaudeHooks(gitRoot: string): Promise<void> {
274→  const claudeDir = join(gitRoot, ".claude");
275→  if (!existsSync(claudeDir)) mkdirSync(claudeDir, { recursive: true });
276→
277→  const settingsPath = join(claudeDir, "settings.json");
278→  const file = Bun.file(settingsPath);
279→  let settings: Record<string, unknown> = {};
280→
281→  if (await file.exists()) {
282→    try {
283→      settings = await file.json();
284→    } catch {
285→      // Corrupted — start fresh
286→    }
287→  }
288→
289→  const hooks = (settings.hooks ?? {}) as Record<string, SettingsHookGroup[]>;
290→  let added = 0;
291→
292→  for (const [event, hookDefs] of Object.entries(BRAIN_HOOKS)) {
293→    hooks[event] ??= [];
294→
295→    const hasBrain = hooks[event].some((group) =>
296→      group.hooks?.some(
297→        (h) => h.command?.startsWith("brain ") || h.prompt?.includes("Brain MCP"),
298→      ),
299→    );
300→
301→    if (!hasBrain) {
302→      hooks[event].push({ hooks: hookDefs as HookEntry[] });
303→      added++;
304→    }
305→  }
306→
307→  settings.hooks = hooks;
308→  await Bun.write(settingsPath, JSON.stringify(settings, null, 2) + "\n");
309→  console.log(`✓ Hooks: .claude/settings.json updated (${added} hooks added)`);
310→}
