316→export const MARKER_START = "<!-- brain-plugin-start -->";
317→export const MARKER_END = "<!-- brain-plugin-end -->";
318→
319→export async function setupClaudeMd(gitRoot: string): Promise<void> {
320→  const claudeMdPath = join(gitRoot, "CLAUDE.md");
321→  const file = Bun.file(claudeMdPath);
322→  let content = "";
323→
324→  if (await file.exists()) {
325→    content = await file.text();
326→  }
327→
328→  const brainBlock = `${MARKER_START}\n${BRAIN_CLAUDE_MD}\n${MARKER_END}`;
329→
330→  const startIdx = content.indexOf(MARKER_START);
331→  const endIdx = content.indexOf(MARKER_END);
332→
333→  if (startIdx !== -1 && endIdx !== -1) {
334→    content = content.slice(0, startIdx) + brainBlock + content.slice(endIdx + MARKER_END.length);
335→  } else {
336→    const separator = content.length > 0 && !content.endsWith("\n\n") ? "\n\n" : "";
337→    content = content + separator + brainBlock + "\n";
338→  }
339→
340→  await Bun.write(claudeMdPath, content);
341→  console.log("✓ CLAUDE.md: Brain plugin instructions added");
342→}
