347→
348→export function installGitHooks(gitRoot?: string): void {
349→  const root = gitRoot ?? findGitRoot(process.cwd());
350→  if (!root) {
351→    console.log("  No .git directory found — skipping git hook installation.");
352→    return;
353→  }
354→
355→  const hooksDir = join(root, ".git", "hooks");
356→  if (!existsSync(hooksDir)) mkdirSync(hooksDir, { recursive: true });
357→
358→  const preCommitPath = join(hooksDir, "pre-commit");
359→  const postCommitPath = join(hooksDir, "post-commit");
360→  const preCommitScript = `#!/bin/sh
361→# Brain pre-commit hook: check for task completion and unlogged decisions
362→brain check-commit
363→`;
364→
365→  if (!existsSync(preCommitPath)) {
366→    writeFileSync(preCommitPath, preCommitScript, { mode: 0o755 });
367→    console.log("✓ Git: pre-commit hook installed");
368→  } else {
369→    console.log("✓ Git: pre-commit hook already exists");
370→  }
371→
372→  // Remove legacy Brain post-commit hook
373→  if (existsSync(postCommitPath)) {
374→    const postCommitContent = readFileSync(postCommitPath, "utf-8");
375→    const isBrainManaged =
376→      postCommitContent.includes("Brain post-commit hook") &&
377→      postCommitContent.includes("brain log-commit");
378→    if (isBrainManaged) {
379→      unlinkSync(postCommitPath);
380→      console.log("  Removed legacy Brain post-commit hook");
381→    }
382→  }
383→}
