389→export async function setupOpencode(gitRoot: string): Promise<void> {
390→  // 1. Create/update opencode.json with brain MCP server
391→  const jsonPath = join(gitRoot, "opencode.json");
392→  const jsonFile = Bun.file(jsonPath);
393→  let opcConfig: Record<string, unknown> = {};
394→
395→  if (await jsonFile.exists()) {
396→    try {
397→      opcConfig = await jsonFile.json();
398→    } catch {
399→      // Corrupted -- start fresh
400→    }
401→  }
402→
403→  // Merge MCP config (preserve existing MCP servers)
404→  const mcp = (opcConfig.mcp ?? {}) as Record<string, unknown>;
405→  mcp.brain = { type: "local", command: ["brain", "mcp"], enabled: true };
406→  opcConfig.mcp = mcp;
407→  opcConfig.$schema ??= "https://opencode.ai/config.json";
408→
409→  // Remove legacy plugin reference
410→  if (Array.isArray(opcConfig.plugins)) {
411→    opcConfig.plugins = (opcConfig.plugins as string[]).filter(
412→      (p) => !p.includes("brain"),
413→    );
414→    if ((opcConfig.plugins as string[]).length === 0) delete opcConfig.plugins;
415→  }
416→
417→  await Bun.write(jsonPath, JSON.stringify(opcConfig, null, 2) + "\n");
418→  console.log("✓ OpenCode: opencode.json updated (brain MCP server configured)");
419→
420→  // 2. Write OPENCODE.md (idempotent overwrite)
421→  await Bun.write(join(gitRoot, "OPENCODE.md"), OPENCODE_MD_CONTENT);
422→  console.log("✓ OpenCode: OPENCODE.md created");
423→
424→  // 3. Clean up legacy plugin file
425→  const legacyPlugin = join(gitRoot, ".opencode", "plugins", "brain.ts");
426→  if (existsSync(legacyPlugin)) {
427→    unlinkSync(legacyPlugin);
428→    console.log("  Removed legacy .opencode/plugins/brain.ts");
429→  }
430→}
