  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withRequestLogging, type RouteHandler } from "../http/request-logging";
  9→import type {
 10→  OrchestratorSessionResult,
 11→  SessionStatusResult,
 12→  AbortSessionResult,
 13→  AcceptSessionResult,
 14→  ReviewResult,
 15→  RejectSessionResult,
 16→  PromptSessionResult,
 17→} from "./session-lifecycle";
 18→import type { SseRegistry } from "../streaming/sse-registry";
 19→
 20→// ---------------------------------------------------------------------------
 21→// Port: Dependencies as function signatures
 22→// ---------------------------------------------------------------------------
 23→
 24→export type OrchestratorRouteDeps = {
 25→  createSession: (
 26→    workspaceId: string,
 27→    taskId: string,
 28→    authToken: string,
 29→  ) => Promise<OrchestratorSessionResult>;
 30→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 31→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 32→  acceptSession: (
 33→    sessionId: string,
 34→    summary: string,
 35→  ) => Promise<AcceptSessionResult>;
 36→  getReview: (sessionId: string) => Promise<ReviewResult>;
 37→  rejectSession: (
 38→    sessionId: string,
 39→    feedback: string,
 40→  ) => Promise<RejectSessionResult>;
 41→  sendPrompt: (
 42→    sessionId: string,
 43→    text: string,
 44→  ) => Promise<PromptSessionResult>;
 45→};
 46→
 47→// ---------------------------------------------------------------------------
 48→// Request body parsing
 49→// ---------------------------------------------------------------------------
 50→
 51→type AssignBody = { taskId?: string };
 52→type AcceptBody = { summary?: string };
 53→type RejectBody = { feedback?: string };
 54→type PromptBody = { text?: string };
 55→
 56→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
 57→  try {
 58→    return (await request.json()) as T;
 59→  } catch {
 60→    return undefined;
 61→  }
 62→}
 63→
 64→function extractAuthToken(request: Request): string {
 65→  return request.headers.get("Cookie") ?? "";
 66→}
 67→
 68→// ---------------------------------------------------------------------------
 69→// Response builders (pure)
 70→// ---------------------------------------------------------------------------
 71→
 72→function assignResponse(
 73→  workspaceId: string,
 74→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
 75→): Response {
 76→  return jsonResponse(
 77→    {
 78→      agentSessionId: value.agentSessionId,
 79→      streamId: value.streamId,
 80→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
 81→    },
 82→    200,
 83→  );
 84→}
 85→
 86→function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
 87→  const result: Record<string, unknown> = {};
 88→  for (const [key, value] of Object.entries(obj)) {
 89→    if (value !== undefined && value !== null) {
 90→      result[key] = value;
 91→    }
 92→  }
 93→  return result as Partial<T>;
 94→}
 95→
 96→function statusResponse(
 97→  sessionId: string,
 98→  value: {
 99→    orchestratorStatus: string;
100→    worktreeBranch?: string;
101→    worktreePath?: string;
102→    startedAt?: string;
103→    lastEventAt?: string;
104→    error?: string;
105→  },
106→): Response {
107→  return jsonResponse(
108→    {
109→      agentSessionId: sessionId,
110→      orchestratorStatus: value.orchestratorStatus,
111→      ...pickDefined({
112→        worktreeBranch: value.worktreeBranch,
113→        worktreePath: value.worktreePath,
114→        startedAt: value.startedAt,
115→        lastEventAt: value.lastEventAt,
116→        error: value.error,
117→      }),
118→    },
119→    200,
120→  );
121→}
122→
123→function acceptResponse(): Response {
124→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
125→}
126→
127→function abortResponse(): Response {
128→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
129→}
130→
131→function reviewResponse(value: {
132→  taskTitle: string;
133→  diff: unknown;
134→  session: unknown;
135→}): Response {
136→  return jsonResponse(value, 200);
137→}
138→
139→function rejectResponse(): Response {
140→  return jsonResponse({ rejected: true, continuing: true }, 200);
141→}
142→
143→function promptResponse(): Response {
144→  return jsonResponse({ delivered: true }, 202);
145→}
146→
147→function sessionErrorResponse(error: {
148→  message: string;
149→  httpStatus: number;
150→}): Response {
151→  return jsonError(error.message, error.httpStatus);
152→}
153→
154→// ---------------------------------------------------------------------------
155→// Route handler factory
156→// ---------------------------------------------------------------------------
157→
158→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
159→  const assign: RouteHandler = async (request) => {
160→    const workspaceId = request.params.workspaceId;
161→    const body = await parseJsonBody<AssignBody>(request);
162→
163→    if (!body?.taskId) {
164→      return jsonError("taskId is required", 400);
165→    }
166→
167→    const authToken = extractAuthToken(request);
168→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
169→
170→    if (!result.ok) {
171→      return sessionErrorResponse(result.error);
172→    }
173→
174→    return assignResponse(workspaceId, result.value);
175→  };
176→
177→  const status: RouteHandler = async (request) => {
178→    const sessionId = request.params.sessionId;
179→    const result = await deps.getSessionStatus(sessionId);
180→
181→    if (!result.ok) {
182→      return sessionErrorResponse(result.error);
183→    }
184→
185→    return statusResponse(sessionId, result.value);
186→  };
187→
188→  const accept: RouteHandler = async (request) => {
189→    const sessionId = request.params.sessionId;
190→    const body = await parseJsonBody<AcceptBody>(request);
191→    const summary = body?.summary ?? "";
192→
193→    const result = await deps.acceptSession(sessionId, summary);
194→
195→    if (!result.ok) {
196→      return sessionErrorResponse(result.error);
197→    }
198→
199→    return acceptResponse();
200→  };
201→
202→  const abort: RouteHandler = async (request) => {
203→    const sessionId = request.params.sessionId;
204→    const result = await deps.abortSession(sessionId);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return abortResponse();
211→  };
212→
213→  const review: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getReview(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return reviewResponse(result.value);
222→  };
223→
224→  const reject: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<RejectBody>(request);
227→
228→    if (!body?.feedback || body.feedback.trim() === "") {
229→      return jsonError("feedback is required", 400);
230→    }
231→
232→    const result = await deps.rejectSession(sessionId, body.feedback);
233→
234→    if (!result.ok) {
235→      return sessionErrorResponse(result.error);
236→    }
237→
238→    return rejectResponse();
239→  };
240→
241→  const prompt: RouteHandler = async (request) => {
242→    const sessionId = request.params.sessionId;
243→    const body = await parseJsonBody<PromptBody>(request);
244→
245→    if (!body?.text || body.text.trim() === "") {
246→      return jsonError("text is required", 400);
247→    }
248→
249→    const result = await deps.sendPrompt(sessionId, body.text);
250→
251→    if (!result.ok) {
252→      return sessionErrorResponse(result.error);
253→    }
254→
255→    return promptResponse();
256→  };
257→
258→  return { assign, status, accept, abort, review, reject, prompt };
259→}
260→
261→// ---------------------------------------------------------------------------
262→// SSE stream route handler factory
263→// ---------------------------------------------------------------------------
264→
265→export type StreamRouteDeps = {
266→  sseRegistry: SseRegistry;
267→};
268→
269→export function createStreamRouteHandler(deps: StreamRouteDeps) {
270→  const stream: RouteHandler = async (request) => {
271→    const sessionId = request.params.sessionId;
272→
273→    if (!sessionId) {
274→      return jsonError("sessionId is required", 400);
275→    }
276→
277→    const streamId = `stream-${sessionId}`;
278→    return deps.sseRegistry.handleStreamRequest(streamId);
279→  };
280→
281→  return { stream };
282→}
283→
284→// ---------------------------------------------------------------------------
285→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
286→// ---------------------------------------------------------------------------
287→
288→export type OrchestratorWiringDeps = {
289→  surreal: import("surrealdb").Surreal;
290→  shellExec: import("./worktree-manager").ShellExec;
291→  brainBaseUrl: string;
292→  sseRegistry?: SseRegistry;
293→};
294→
295→export function wireOrchestratorRoutes(
296→  wiringDeps: OrchestratorWiringDeps,
297→): {
298→  assign: RouteHandler;
299→  status: RouteHandler;
300→  accept: RouteHandler;
301→  abort: RouteHandler;
302→  review: RouteHandler;
303→  reject: RouteHandler;
304→  prompt: RouteHandler;
305→  stream?: RouteHandler;
306→} {
307→  // Lazy imports to keep module boundary clean
308→  const lifecycleImport = import("./session-lifecycle");
309→  const queriesImport = import("../mcp/mcp-queries");
310→  const guardImport = import("./assignment-guard");
311→  const stallDetectorImport = import("./stall-detector");
312→
313→  // Helper: resolve repo_path from workspace record
314→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
315→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
316→      `SELECT repo_path FROM $ws;`,
317→      { ws: workspaceRecord },
318→    );
319→    const repoPath = rows[0]?.repo_path;
320→    if (!repoPath) {
321→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
322→    }
323→    return repoPath;
324→  };
325→
326→  // Use mock spawn for acceptance tests, production spawn otherwise
327→  const spawnOpenCodeImport = process.env.ORCHESTRATOR_MOCK_OPENCODE === "true"
328→    ? Promise.resolve({
329→        spawnOpenCode: async () => ({
330→          sessionId: crypto.randomUUID(),
331→          abort: () => {},
332→          sendPrompt: async () => {},
333→          eventStream: (async function* () {})(),
334→        }),
335→      })
336→    : import("./spawn-opencode");
337→
338→  const routeDeps: OrchestratorRouteDeps = {
339→    createSession: async (workspaceId, taskId, authToken) => {
340→      const [lifecycle, queries, guard, { spawnOpenCode }, stallDetector] = await Promise.all([
341→        lifecycleImport,
342→        queriesImport,
343→        guardImport,
344→        spawnOpenCodeImport,
345→        stallDetectorImport,
346→      ]);
347→      const result = await lifecycle.createOrchestratorSession({
348→        surreal: wiringDeps.surreal,
349→        shellExec: wiringDeps.shellExec,
350→        brainBaseUrl: wiringDeps.brainBaseUrl,
351→        workspaceId,
352→        taskId,
353→        authToken,
354→        validateAssignment: guard.validateAssignment,
355→        createAgentSession: queries.createAgentSession,
356→        spawnOpenCode,
357→      });
358→
359→      // Wire SSE stream + event iteration on success
360→      if (result.ok && wiringDeps.sseRegistry) {
361→        const { agentSessionId, streamId } = result.value;
362→        wiringDeps.sseRegistry.registerMessage(streamId);
363→
364→        const handle = lifecycle.getHandle(agentSessionId);
365→        if (handle) {
366→          const { RecordId } = await import("surrealdb");
367→          lifecycle.startEventIteration(
368→            {
369→              emitEvent: wiringDeps.sseRegistry.emitEvent,
370→              updateSessionStatus: async (sid, status, error) => {
371→                const rec = new RecordId("agent_session", sid);
372→                await wiringDeps.surreal.update(rec).merge({
373→                  orchestrator_status: status,
374→                  ...(error !== undefined ? { error } : {}),
375→                });
376→              },
377→              updateLastEventAt: async (sid) => {
378→                const rec = new RecordId("agent_session", sid);
379→                await wiringDeps.surreal.update(rec).merge({
380→                  last_event_at: new Date().toISOString(),
381→                });
382→              },
383→              getSessionStatus: async (sid) => {
384→                const rec = new RecordId("agent_session", sid);
385→                const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
386→                return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
387→              },
388→              startStallDetector: (sid, stId) =>
389→                stallDetector.startStallDetector(
390→                  {
391→                    abortSession: async (abortSid) => {
392→                      const abortResult = await lifecycle.abortOrchestratorSession({
393→                        surreal: wiringDeps.surreal,
394→                        shellExec: wiringDeps.shellExec,
395→                        resolveRepoRoot,
396→                        sessionId: abortSid,
397→                        endAgentSession: queries.endAgentSession,
398→                      });
399→                      return abortResult;
400→                    },
401→                    createObservation: async () => {},
402→                    emitEvent: wiringDeps.sseRegistry!.emitEvent,
403→                  },
404→                  stallDetector.DEFAULT_STALL_CONFIG,
405→                  sid,
406→                  stId,
407→                ),
408→            },
409→            handle.eventStream,
410→            streamId,
411→            agentSessionId,
412→          );
413→        }
414→      }
415→
416→      return result;
417→    },
418→
419→    getSessionStatus: async (sessionId) => {
420→      const lifecycle = await lifecycleImport;
421→      return lifecycle.getOrchestratorSessionStatus({
422→        surreal: wiringDeps.surreal,
423→        sessionId,
424→      });
425→    },
426→
427→    abortSession: async (sessionId) => {
428→      const [lifecycle, queries] = await Promise.all([
429→        lifecycleImport,
430→        queriesImport,
431→      ]);
432→      return lifecycle.abortOrchestratorSession({
433→        surreal: wiringDeps.surreal,
434→        shellExec: wiringDeps.shellExec,
435→        resolveRepoRoot,
436→        sessionId,
437→        endAgentSession: queries.endAgentSession,
438→      });
439→    },
440→
441→    acceptSession: async (sessionId, summary) => {
442→      const [lifecycle, queries] = await Promise.all([
443→        lifecycleImport,
444→        queriesImport,
445→      ]);
446→      return lifecycle.acceptOrchestratorSession({
447→        surreal: wiringDeps.surreal,
448→        sessionId,
449→        summary,
450→        endAgentSession: queries.endAgentSession,
451→      });
452→    },
453→
454→    getReview: async (sessionId) => {
455→      const [lifecycle, worktreeManager] = await Promise.all([
456→        lifecycleImport,
457→        import("./worktree-manager"),
458→      ]);
459→      return lifecycle.getOrchestratorReview({
460→        surreal: wiringDeps.surreal,
461→        sessionId,
462→        resolveRepoRoot,
463→        getDiff: (repoRoot: string, branchName: string) =>
464→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
465→        getTaskTitle: async (taskId: string) => {
466→          const { RecordId } = await import("surrealdb");
467→          const taskRecord = new RecordId("task", taskId);
468→          const rows = (await wiringDeps.surreal.query(
469→            `SELECT title FROM $task;`,
470→            { task: taskRecord },
471→          )) as Array<Array<{ title: string }>>;
472→          return rows[0]?.[0]?.title ?? "";
473→        },
474→      });
475→    },
476→
477→    rejectSession: async (sessionId, feedback) => {
478→      const lifecycle = await lifecycleImport;
479→      return lifecycle.rejectOrchestratorSession({
480→        surreal: wiringDeps.surreal,
481→        sessionId,
482→        feedback,
483→      });
484→    },
485→
486→    sendPrompt: async (sessionId, text) => {
487→      const lifecycle = await lifecycleImport;
488→      return lifecycle.sendSessionPrompt({
489→        surreal: wiringDeps.surreal,
490→        sessionId,
491→        text,
492→      });
493→    },
494→  };
495→
496→  const handlers = createOrchestratorRouteHandlers(routeDeps);
497→
498→  const streamHandler = wiringDeps.sseRegistry
499→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
500→    : undefined;
501→
502→  return {
503→    assign: withRequestLogging("orchestrator.assign", "POST", handlers.assign),
504→    status: withRequestLogging("orchestrator.status", "GET", handlers.status),
505→    accept: withRequestLogging("orchestrator.accept", "POST", handlers.accept),
506→    abort: withRequestLogging("orchestrator.abort", "POST", handlers.abort),
507→    review: withRequestLogging("orchestrator.review", "GET", handlers.review),
508→    reject: withRequestLogging("orchestrator.reject", "POST", handlers.reject),
509→    prompt: withRequestLogging("orchestrator.prompt", "POST", handlers.prompt),
510→    ...(streamHandler
511→      ? { stream: withRequestLogging("orchestrator.stream", "GET", streamHandler.stream) }
512→      : {}),
513→  };
514→}
515→

  1→/**
  2→ * Stall detector: monitors agent session activity and step counts.
  3→ *
  4→ * Pure check functions (checkStallTimeout, checkStepLimit) + effectful handle
  5→ * (startStallDetector) that manages timers and triggers abort/observation.
  6→ *
  7→ * Timer and clock are injectable for testability.
  8→ */
  9→import type { StreamEvent, AgentStallWarningEvent } from "../../shared/contracts";
 10→import type { AbortSessionResult } from "./session-lifecycle";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Configuration
 14→// ---------------------------------------------------------------------------
 15→
 16→export type StallDetectorConfig = {
 17→  stallTimeoutMs: number;     // default: 300_000 (5 minutes)
 18→  maxSteps: number;           // default: 100
 19→  checkIntervalMs: number;    // default: 30_000 (30 seconds)
 20→};
 21→
 22→export const DEFAULT_STALL_CONFIG: StallDetectorConfig = {
 23→  stallTimeoutMs: 300_000,
 24→  maxSteps: 100,
 25→  checkIntervalMs: 30_000,
 26→};
 27→
 28→// ---------------------------------------------------------------------------
 29→// Ports: dependencies as function signatures
 30→// ---------------------------------------------------------------------------
 31→
 32→export type ObservationInput = {
 33→  text: string;
 34→  severity: "info" | "warning" | "conflict";
 35→  category: string;
 36→  sourceAgent: string;
 37→};
 38→
 39→export type StallDetectorDeps = {
 40→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 41→  createObservation: (input: ObservationInput) => Promise<void>;
 42→  emitEvent: (streamId: string, event: StreamEvent) => void;
 43→};
 44→
 45→// ---------------------------------------------------------------------------
 46→// Injectable clock/timer for testability
 47→// ---------------------------------------------------------------------------
 48→
 49→export type Clock = {
 50→  now: () => number;
 51→  setInterval: (callback: () => void, ms: number) => ReturnType<typeof globalThis.setInterval>;
 52→  clearInterval: (id: ReturnType<typeof globalThis.setInterval>) => void;
 53→};
 54→
 55→const SYSTEM_CLOCK: Clock = {
 56→  now: () => Date.now(),
 57→  setInterval: globalThis.setInterval.bind(globalThis),
 58→  clearInterval: globalThis.clearInterval.bind(globalThis),
 59→};
 60→
 61→// ---------------------------------------------------------------------------
 62→// Handle
 63→// ---------------------------------------------------------------------------
 64→
 65→export type StallDetectorHandle = {
 66→  recordActivity: () => void;
 67→  incrementStepCount: () => void;
 68→  stop: () => void;
 69→};
 70→
 71→// ---------------------------------------------------------------------------
 72→// Pure check: timeout
 73→// ---------------------------------------------------------------------------
 74→
 75→export type StallCheckInput = {
 76→  lastActivityAt: number;
 77→  nowMs: number;
 78→  stallTimeoutMs: number;
 79→};
 80→
 81→export type StallCheckResult = {
 82→  stalled: boolean;
 83→  stallDurationMs?: number;
 84→};
 85→
 86→export function checkStallTimeout(input: StallCheckInput): StallCheckResult {
 87→  const elapsed = input.nowMs - input.lastActivityAt;
 88→  if (elapsed > input.stallTimeoutMs) {
 89→    return { stalled: true, stallDurationMs: elapsed };
 90→  }
 91→  return { stalled: false };
 92→}
 93→
 94→// ---------------------------------------------------------------------------
 95→// Pure check: step limit
 96→// ---------------------------------------------------------------------------
 97→
 98→export type StepLimitResult = {
 99→  exceeded: boolean;
100→  currentSteps: number;
101→  maxSteps: number;
102→};
103→
104→export function checkStepLimit(currentSteps: number, maxSteps: number): StepLimitResult {
105→  return {
106→    exceeded: currentSteps > maxSteps,
107→    currentSteps,
108→    maxSteps,
109→  };
110→}
111→
112→// ---------------------------------------------------------------------------
113→// Effectful handle factory
114→// ---------------------------------------------------------------------------
115→
116→export function startStallDetector(
117→  deps: StallDetectorDeps,
118→  config: StallDetectorConfig,
119→  sessionId: string,
120→  streamId: string,
121→  clock: Clock = SYSTEM_CLOCK,
122→): StallDetectorHandle {
123→  let stopped = false;
124→  let aborted = false;
125→  let lastActivityAt = clock.now();
126→  let stepCount = 0;
127→
128→  async function handleStall(reason: string, observation: string): Promise<void> {
129→    if (aborted || stopped) return;
130→    aborted = true;
131→
132→    const stallWarning: AgentStallWarningEvent = {
133→      type: "agent_stall_warning",
134→      sessionId,
135→      lastEventAt: new Date(lastActivityAt).toISOString(),
136→      stallDurationSeconds: Math.round((clock.now() - lastActivityAt) / 1000),
137→    };
138→
139→    deps.emitEvent(streamId, stallWarning);
140→    await deps.abortSession(sessionId);
141→    await deps.createObservation({
142→      text: observation,
143→      severity: "warning",
144→      category: "stall_detection",
145→      sourceAgent: "orchestrator",
146→    });
147→  }
148→
149→  function checkTimeout(): void {
150→    if (stopped || aborted) return;
151→
152→    const result = checkStallTimeout({
153→      lastActivityAt,
154→      nowMs: clock.now(),
155→      stallTimeoutMs: config.stallTimeoutMs,
156→    });
157→
158→    if (result.stalled) {
159→      const durationSec = Math.round((result.stallDurationMs ?? 0) / 1000);
160→      handleStall(
161→        "timeout",
162→        `Agent session stalled: no activity for ${durationSec} seconds`,
163→      );
164→    }
165→  }
166→
167→  const intervalId = clock.setInterval(checkTimeout, config.checkIntervalMs);
168→
169→  return {
170→    recordActivity(): void {
171→      if (stopped) return;
172→      lastActivityAt = clock.now();
173→    },
174→
175→    incrementStepCount(): void {
176→      if (stopped || aborted) return;
177→      stepCount += 1;
178→
179→      const result = checkStepLimit(stepCount, config.maxSteps);
180→      if (result.exceeded) {
181→        handleStall(
182→          "step_limit",
183→          `Agent session exceeded maximum step count: ${stepCount}/${config.maxSteps} steps`,
184→        );
185→      }
186→    },
187→
188→    stop(): void {
189→      stopped = true;
190→      clock.clearInterval(intervalId);
191→    },
192→  };
193→}
